/**
 * Channel Plugin SDK — helper to define channel plugins for external extensions.
 * Provides a type-safe builder for constructing ChannelPlugin instances.
 */

import type { ChannelCapabilities, ChannelId, ChannelMeta } from './types/core.ts'
import type { ChannelPlugin } from './types/plugin.ts'
import type {
    ChannelConfigAdapter,
    ChannelGatewayAdapter,
    ChannelOutboundAdapter,
    ChannelSecurityAdapter,
    ChannelPairingAdapter,
    ChannelCommandAdapter,
    ChannelElevatedAdapter,
    ChannelMentionAdapter,
    ChannelGroupAdapter,
    ChannelThreadingAdapter,
    ChannelStreamingAdapter,
    ChannelMessagingAdapter,
    ChannelDirectoryAdapter,
    ChannelResolverAdapter,
    ChannelMessageActionAdapter,
    ChannelAgentPromptAdapter,
    ChannelAgentToolFactory,
    ChannelStatusAdapter,
    ChannelSetupAdapter,
    ChannelOnboardingAdapter,
    ChannelAuthAdapter,
    ChannelHeartbeatAdapter,
    ChannelConfigSchema,
} from './types/adapters.ts'

export interface PluginMetadata {
    name: string
    version: string
    description?: string
    author?: string
}

export interface DefineChannelPluginOptions<ResolvedAccount = unknown> {
    id: ChannelId
    meta: ChannelMeta
    capabilities: ChannelCapabilities
    pluginMetadata?: PluginMetadata

    config: ChannelConfigAdapter<ResolvedAccount>
    configSchema?: ChannelConfigSchema
    setup?: ChannelSetupAdapter
    onboarding?: ChannelOnboardingAdapter

    gateway?: ChannelGatewayAdapter<ResolvedAccount>
    outbound?: ChannelOutboundAdapter
    auth?: ChannelAuthAdapter
    heartbeat?: ChannelHeartbeatAdapter

    security?: ChannelSecurityAdapter
    pairing?: ChannelPairingAdapter
    commands?: ChannelCommandAdapter
    elevated?: ChannelElevatedAdapter

    mentions?: ChannelMentionAdapter
    groups?: ChannelGroupAdapter
    threading?: ChannelThreadingAdapter
    streaming?: ChannelStreamingAdapter
    messaging?: ChannelMessagingAdapter

    directory?: ChannelDirectoryAdapter
    resolver?: ChannelResolverAdapter
    actions?: ChannelMessageActionAdapter
    agentPrompt?: ChannelAgentPromptAdapter
    agentTools?: ChannelAgentToolFactory
    status?: ChannelStatusAdapter

    defaults?: { queue?: { debounceMs?: number } }
    reload?: { configPrefixes: string[] }
    gatewayMethods?: string[]
}

export function defineChannelPlugin<ResolvedAccount = unknown>(
    opts: DefineChannelPluginOptions<ResolvedAccount>,
): ChannelPlugin<ResolvedAccount> {
    const { pluginMetadata: _, ...plugin } = opts
    return plugin
}
